var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"죄송해요! 정말 죄송합니다, 사장님!","JPN":"すみません！　本当にすみません、社長！","ENG":"My apologies! I truly am, sir!","TWN":"老闆對不起！真的很對不起！"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"설마 주인이 따로 있는 사무실일 줄은 몰랐어요. 뭐라 드릴 말씀이 없습니다.","JPN":"まさか持ち主がいる事務所だとは思わなかったんです。申し訳ありません。","ENG":"We didn't know this office was still in use. I don't have any words to express how sorry we are.","TWN":"我們不知道這間辦公室是你的，非常抱歉。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 너무 미안해할 것 없네.","JPN":"はは、あまり悪く思うことはない。","ENG":"Ha ha, there's no need to be that sorry.","TWN":"哈哈，沒那麼嚴重。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 저 두 사람, 꽤 본격적으로 리그를 노리던 모양이군. 직원도 구하고.","JPN":"それよりあの二人、かなり本気でリーグを狙っていたようだね。職員まで雇うとは。","ENG":"By the way, those two seem to want to participate in the League. They even hired employees.","TWN":"倒是她們二個，好像非常看重聯賽，還為此徵人進來。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그러니까요. 너무 뻔뻔해서 깜빡 속았어요.","JPN":"本当にそうですね。あまりに堂々としていたので騙されてしまいました。","ENG":"I know. They were so shameless about it that I actually fell for it.","TWN":"可不是嘛，她們演得太像回事，連我也被騙過去。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"맨주먹으로 시작하는 태스크포스인 줄 알고 굳이 연봉까지 낮춰서 들어왔더니만….","JPN":"ゼロからスタートするタスクフォースだと思って、年俸まで妥協して入社したんですが……","ENG":"And here I thought it was a newly formed TASKFORCE. I even took a pay cut just to join...","TWN":"我還以為是白手起家的特遣勢力，才自願減薪加入的……"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"스키너도 결국 어른이었네요. 자본의 힘 앞에 천박하게 아양 떠는 꼴 좀 보세요.","JPN":"スキナーも結局は大人だったんですね。そうやって資本力の前では卑しく尻尾を振って。","ENG":"So you're just like any other adult, aren't you, Skinner? Kneeling down to the power of money.","TWN":"史金納說到底也是大人呢。你看她在資本主義面前那副卑躬屈膝的樣子。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"벌 서는데 궁시렁거리지 말고 손이나 잘 들어, 꼬맹이.","JPN":"罰受けてるのにぶつぶつ言わないで、ちゃんと手を上げろよ。おこちゃま。","ENG":"We're being punished right now, so shut up and keep your arms up, kid.","TWN":"你還在罰站呢，別嘀嘀咕咕的，把手舉好，小鬼。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"자기는 아닌 척 하지 마세요. 라이카도 벌 서고 있으면서.","JPN":"ライカが言うことじゃないでしょ。一緒に罰を受けてる身で。","ENG":"Don't act like you aren't. You're receiving the same punishment too, Laika.","TWN":"說得好像只有罰我一樣，萊卡你不也是在罰站嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"너희는 틈만 나면 티격태격이니?","JPN":"あなたたち、暇さえあればケンカばかりね。","ENG":"Do you two always bicker about everything?","TWN":"你們一有空就要鬥嘴嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"대체 내 월급은 어떻게 주려고 한 거야?","JPN":"いったい私の給料はどうやって支払うつもりだったの？","ENG":"How were you even planning on paying me?","TWN":"你們究竟打算怎麼付我工資？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그거야 뭐 아르바이트라거나….","JPN":"そりゃあ、まあ、バイトとか……","ENG":"Well, through part-time jobs and whatnot...","TWN":"那個，我們打算找個打工或是…"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"리그 상금을 따서 갚으려고 했어요.","JPN":"リーグの賞金で返すつもりでした。","ENG":"We were going to pay you after claiming the League's prize money.","TWN":"我會用聯賽贏來的獎金付你薪水。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"너희들 정말…….","JPN":"あきれた……","ENG":"Oh, come on...","TWN":"你們真的是……"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아니다. 그냥 말을 말자.","JPN":"いいえ。もういいわ。","ENG":"Nope. I should stop talking.","TWN":"算了，還是別說了。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"왜 난 매번 이 모양이람. 기껏 새출발하나 했더니.","JPN":"私ってなんでいつもこうなのかしら？　せっかく新しく出発できると思ったのに。","ENG":"What does this always happen to me? I thought it would be a fresh start.","TWN":"為什麼每次都這樣，我好不容易想要重新開始……"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"비슷한 유니폼을 입고 계신 것 같은데… 혹시 언니도 현장직이세요?","JPN":"似たようなユニフォームを着てますけど……もしかして、あなたも現場職なんですか？","ENG":"You're wearing a uniform similar to them... Do you also work in the field?","TWN":"我看你們穿著差不多的制服……姊姊也是參賽選手嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};